-- ============================== 2b. Bootstrap pirate camp gen B (730000085) ==============================
-- 730001001 deletes 730000085 but never re-creates it; we create it here
-- BEFORE sections 3/4 reference it in their INSERT statements.
ON DUPLICATE KEY UPDATE `last_Modified` = UTC_TIMESTAMP();





-- Update 730000091 name from boss picker to camp gen
UPDATE `weenie_properties_string` SET `value` = 'T11 Pirate Camp Gen (Skippy)' WHERE `object_Id` = 730000091 AND `type` = 1;

